import json
from collections import defaultdict
keys_at_depth = defaultdict(set)
def walk(o, path):
    if isinstance(o, dict):
        for k,v in o.items():
            keys_at_depth[path].add(k)
            walk(v, path + '.' + k if path else k)
    elif isinstance(o, list):
        for item in o:
            walk(item, path + '[]')
with open('/Users/bhyslop/projects/rbm_alpha_recipemuster/.claude/jjm/jjg_gallops.json') as f:
    g = json.load(f)
walk(g, '')
for path in sorted(keys_at_depth.keys()):
    print(f'{path or \"(root)\"}: {sorted(keys_at_depth[path])}')"

python3 -c "
import json
keys = set()
optional_keys = set()
def walk(o):
    if isinstance(o, dict):
        for k,v in o.items():
            keys.add(k)
            walk(v)
    elif isinstance(o, list):
        for item in o:
            walk(item)
with open('/Users/bhyslop/projects/rbm_alpha_recipemuster/.claude/jjm/jjg_gallops.json') as f:
    g = json.load(f)
walk(g)
# Filter out heat/pace identity keys (₣ ₢)
real_keys = sorted(k for k in keys if not k.startswith('₣') and not k.startswith('₢'))
print('JSON tag vocabulary used in jjg_gallops.json:')
for k in real_keys:
    print(f'  {k}')
print()
# Check enum string values for state/status
states = set()
statuses = set()
def walk2(o):
    if isinstance(o, dict):
        if 'state' in o and isinstance(o['state'], str):
            states.add(o['state'])
        if 'status' in o and isinstance(o['status'], str):
            statuses.add(o['status'])
        for v in o.values():
            walk2(v)
    elif isinstance(o, list):
        for item in o:
            walk2(item)
walk2(g)
print(f'state values: {sorted(states)}')
print(f'status values: {sorted(statuses)}')"

